mapper.delete:
DELETE FROM long_term_memories USING (
    SELECT id FROM long_term_memories WHERE user_id = #{userId} ORDER BY created_at ASC LIMIT #{count}
) AS sub WHERE long_term_memories.id = sub.id

mapper.select:
SELECT a.id FROM long_term_memories a
LEFT JOIN long_term_memories b ON a.user_id = b.user_id AND a.id != b.id AND a.embedding IS NOT NULL AND b.embedding IS NOT NULL
WHERE a.user_id = #{userId}
GROUP BY a.id, a.created_at
ORDER BY COALESCE(AVG(1 - (a.embedding <=> b.embedding)), 0) ASC, a.created_at ASC
LIMIT #{count}

SELECT id, user_id, content, source_type, source_id, embedding, created_at
FROM long_term_memories WHERE user_id = #{userId} AND embedding IS NOT NULL
ORDER BY 1 - (embedding <=> #{queryVec}::vector) DESC LIMIT #{limit}
